INSERT INTO estimulos_desenvolvimento (id, idade_inicial_meses, idade_final_meses, area, titulo, descricao, cuidado, fonte, versao_catalogo, ativo) VALUES
('30000000-0000-0000-0000-000000000001',2,2,'SOCIAL_EMOCIONAL','Atividade para: Acalma-se no colo ou com a voz de quem cuida.','Praticar pele a pele e colo prolongado em momentos calmos; falar ou cantar baixinho perto do rosto do bebê antes de ele chorar, criando associação entre voz e alívio.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000002',2,2,'SOCIAL_EMOCIONAL','Atividade para: Sorri ao ver o rosto de alguém.','Aproximar o rosto a 20–30 cm, sorrir amplamente e esperar alguns segundos antes de repetir, dando tempo de resposta ao bebê.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000003',2,2,'LINGUAGEM_COMUNICACAO','Atividade para: Faz sons além do choro.','Responder a qualquer vocalização imitando o som de volta, criando pequenas ''conversas'' com pausas de espera.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000004',2,2,'LINGUAGEM_COMUNICACAO','Atividade para: Reage a sons altos.','Observar reação a sons do ambiente (campainha, latido). Ausência total de reação a sons altos inesperados merece avaliação de triagem auditiva, além da estimulação.','A ausência de reação a sons altos inesperados merece conversa com o pediatra. A orientação individual aparece na tela quando a família marca Ainda não.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000005',2,2,'COGNITIVO','Atividade para: Presta atenção a rostos.','Momentos de troca ''cara a cara'' sem telas ou brinquedos, alternando expressões devagar (surpresa, sorriso).','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000006',2,2,'COGNITIVO','Atividade para: Segue objetos com o olhar por curtos períodos.','Mover um objeto de alto contraste (preto/branco ou vermelho) lentamente a ~25 cm dos olhos, da linha média para os lados.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000007',2,2,'MOTOR','Atividade para: Levanta a cabeça brevemente quando está de bruços e acordada.','Tummy time curto (1–3 min, várias vezes ao dia) sobre o antebraço do adulto ou um rolo, sempre supervisionado e com o bebê acordado.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000008',2,2,'MOTOR','Atividade para: Movimenta braços e pernas dos dois lados do corpo.','Observar simetria durante trocas de fralda e banho. Assimetria visível é sinal de alerta motor, além de alvo de estimulação.','Assimetria visível entre os lados merece conversa com o pediatra. A orientação individual aparece na tela quando a família marca Ainda não.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000009',4,4,'SOCIAL_EMOCIONAL','Atividade para: Sorri espontaneamente para chamar atenção.','Criar pausas na interação (parar de falar/brincar por alguns segundos) para observar se o bebê tenta reengajar com sorriso ou som.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000010',4,4,'SOCIAL_EMOCIONAL','Atividade para: Começa a imitar expressões faciais.','Fazer caretas exageradas e lentas (boca aberta, língua para fora) de frente para o bebê, repetindo várias vezes.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000011',4,4,'LINGUAGEM_COMUNICACAO','Atividade para: Faz arrulhos em uma troca de sons com outra pessoa.','Fazer ''conversas'' de vogais: imitar o som do bebê e esperar a vez dele responder.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000012',4,4,'LINGUAGEM_COMUNICACAO','Atividade para: Vira-se para vozes familiares.','Chamar o bebê pelo nome vindo de lados diferentes, fora do campo visual, para estimular localização auditiva.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000013',4,4,'COGNITIVO','Atividade para: Observa as próprias mãos com interesse.','Colocar pulseirinhas de guizo leve ou luvinhas com textura para chamar atenção às mãos durante o brincar livre.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000014',4,4,'COGNITIVO','Atividade para: Segue objetos em movimento de um lado a outro.','Balançar um chocalho ou objeto colorido em arco horizontal e depois vertical, incentivando o rastreamento visual.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000015',4,4,'MOTOR','Atividade para: Sustenta a cabeça firme quando está sentada com apoio.','Sentar o bebê apoiado (colo ou almofada) em curtos períodos supervisionados para fortalecer a musculatura cervical.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000016',4,4,'MOTOR','Atividade para: Rola de bruços para as costas.','Durante o tummy time, posicionar um brinquedo interessante de lado para incentivar o giro; auxiliar suavemente o quadril se necessário.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000017',6,6,'SOCIAL_EMOCIONAL','Atividade para: Reconhece pessoas familiares e pode reagir diferente a pessoas desconhecidas.','Comportamento esperado; orientar os pais a validar a reação, sem forçar aproximação com desconhecidos.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000018',6,6,'SOCIAL_EMOCIONAL','Atividade para: Ri alto ou gargalha.','Brincadeiras físicas leves e previsíveis (cócegas suaves, cadê-achou) que geram expectativa e surpresa.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000019',6,6,'LINGUAGEM_COMUNICACAO','Atividade para: Faz sons de vogais e consoantes.','Narrar rotinas em voz alta e imitar os sons que o bebê já produz, incentivando novas combinações.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000020',6,6,'COGNITIVO','Atividade para: Leva objetos à boca para explorar.','Oferecer brinquedos de texturas variadas e seguros (mordedores, panos). Comportamento esperado, não deve ser impedido.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000021',6,6,'COGNITIVO','Atividade para: Estica o braço para alcançar um objeto.','Posicionar brinquedos ligeiramente fora do alcance, sentado ou de bruços, incentivando o esforço de alcançar.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000022',6,6,'MOTOR','Atividade para: Senta sem apoio.','Sentar o bebê cercado de almofadas, com brinquedos ao redor, aumentando gradualmente o tempo sem apoio das mãos.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000023',6,6,'MOTOR','Atividade para: Sustenta peso nas pernas quando apoiada em pé.','Segurar o bebê em pé no colo, sobre superfície firme, por curtos períodos, sentindo o apoio do peso nas pernas.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000024',9,9,'SOCIAL_EMOCIONAL','Atividade para: Pode estranhar pessoas novas.','Comportamento esperado (ansiedade de estranho); orientar os pais a validar, não forçar aproximação.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000025',9,9,'LINGUAGEM_COMUNICACAO','Atividade para: Reage quando é chamada pelo nome.','Chamar o nome do bebê antes de iniciar interações (troca, refeição), esperando resposta antes de prosseguir.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000026',9,9,'LINGUAGEM_COMUNICACAO','Atividade para: Balbucia em sequência, como ''dadada'' ou ''bababa''.','Repetir e expandir os balbucios do bebê em ''conversas'' ritmadas, incluindo durante rotinas de cuidado.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000027',9,9,'LINGUAGEM_COMUNICACAO','Atividade para: Aponta ou vocaliza para pedir algo.','Esperar um pouco antes de atender pedidos, dando tempo para o bebê tentar se comunicar (gesto ou som) antes de entregar o objeto.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000028',9,9,'COGNITIVO','Atividade para: Procura um objeto parcialmente escondido.','Brincar de esconder parcialmente um brinquedo sob um pano, na frente do bebê, incentivando-o a puxar o pano.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000029',9,9,'COGNITIVO','Atividade para: Bate dois objetos um contra o outro.','Oferecer dois objetos pequenos e seguros (blocos, colheres) e demonstrar o gesto de bater um no outro.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000030',9,9,'MOTOR','Atividade para: Fica em pé com apoio ou anda se apoiando em móveis.','Organizar o ambiente com móveis baixos e seguros em sequência, incentivando deslocamento apoiado (cruising).','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000031',9,9,'MOTOR','Atividade para: Engatinha ou se desloca de alguma forma.','Colocar brinquedos motivadores fora do alcance no chão, incentivando qualquer forma de deslocamento (engatinhar, arrastar, rolar). Nota: uma parcela de bebês nunca engatinha e passa direto para o andar apoiado — variação normal, desde que haja algum deslocamento autônomo.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000032',12,12,'SOCIAL_EMOCIONAL','Atividade para: Brinca de dar e receber objetos.','Brincadeiras simples de dá e recebe com bola ou objeto, alternando os turnos com entusiasmo.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000033',12,12,'LINGUAGEM_COMUNICACAO','Atividade para: Acena ''tchau''.','Modelar o gesto de tchau em toda despedida real, e reforçar com brincadeiras de cadê/tchau com bonecos.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000034',12,12,'LINGUAGEM_COMUNICACAO','Atividade para: Fala uma primeira palavra com intenção de se comunicar.','Nomear consistentemente pessoas e objetos do cotidiano, esperando e valorizando qualquer tentativa de imitação.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000035',12,12,'LINGUAGEM_COMUNICACAO','Atividade para: Aponta para pedir algo.','Ao perceber o interesse do bebê em algo, modelar o gesto de apontar antes de entregar o item.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000036',12,12,'COGNITIVO','Atividade para: Coloca e retira objetos de um recipiente.','Oferecer um pote ou caixa com objetos seguros para encher e esvaziar livremente.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000037',12,12,'COGNITIVO','Atividade para: Imita gestos simples.','Brincadeiras de imitação como bater palmas e mandar beijo, observando se a criança tenta reproduzir.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000038',12,12,'MOTOR','Atividade para: Fica em pé sozinho.','Incentivar momentos de brincadeira em pé apoiada em móvel, retirando o apoio por segundos enquanto segura um brinquedo motivador.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000039',12,12,'MOTOR','Atividade para: Anda sozinho, sem apoio.','Caminhar de frente para a criança, a pequena distância, com braços abertos e incentivo verbal, sem segurar as mãos.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000040',12,12,'MOTOR','Atividade para: Usa a pinça entre polegar e indicador para pegar objetos pequenos.','Oferecer alimentos cortados em tiras ou pedaços pequenos e macios (ex.: banana, pera cozida, macarrão bem cozido) — nunca inteiros, redondos ou duros (uva, tomate-cereja, amendoim, pipoca), pelo risco de engasgo. Para objetos não comestíveis, usar itens grandes o bastante para não caber inteiros na boca, sempre supervisionado.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000041',15,15,'SOCIAL_EMOCIONAL','Atividade para: Demonstra afeto espontaneamente.','Modelar afeto (abraços, beijos) em momentos de calma e nomear o sentimento.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000042',15,15,'SOCIAL_EMOCIONAL','Atividade para: Ajuda a se vestir.','Durante o vestir, pedir pequenas colaborações (ex.: ''levanta o bracinho'') e dar tempo para a criança tentar.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000043',15,15,'LINGUAGEM_COMUNICACAO','Atividade para: Usa pelo menos três palavras isoladas.','Nomear objetos do interesse imediato da criança repetidamente, em situações reais, esperando tentativas de fala.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000044',15,15,'LINGUAGEM_COMUNICACAO','Atividade para: Segue uma instrução simples sem gesto de apoio.','Dar instruções curtas em contextos familiares (ex.: ''pega a bola'') sem apontar, observando a compreensão.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000045',15,15,'COGNITIVO','Atividade para: Usa objetos do dia a dia de forma esperada, como copo ou escova.','Oferecer objetos reais durante brincadeiras de faz-de-conta ou rotina, modelando o uso correto.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000046',15,15,'COGNITIVO','Atividade para: Empilha pelo menos dois objetos.','Brincar de empilhar blocos grandes junto com a criança, celebrando cada tentativa.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000047',15,15,'MOTOR','Atividade para: Anda com boa estabilidade, sem cair com frequência.','Proporcionar superfícies variadas (grama, tapete, chão liso) supervisionadas para praticar equilíbrio.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000048',15,15,'MOTOR','Atividade para: Sobe alguns degraus baixos com ajuda.','Praticar subida de 1–2 degraus seguros de mãos dadas, ou em escada de brinquedo/step baixo.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000049',18,18,'SOCIAL_EMOCIONAL','Atividade para: Brinca perto de outras crianças.','Promover encontros com outras crianças (parquinho, playdates), sem exigir interação direta — brincar ''paralelo'' é esperado nessa idade.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000050',18,18,'SOCIAL_EMOCIONAL','Atividade para: Aponta para mostrar algo interessante a outra pessoa.','Durante passeios, apontar para coisas interessantes e nomear, incentivando a criança a fazer o mesmo e checar sua reação.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000051',18,18,'LINGUAGEM_COMUNICACAO','Atividade para: Tem vocabulário de pelo menos dez palavras.','Ler livros de figuras nomeando objetos repetidamente, e expandir frases da criança.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000052',18,18,'LINGUAGEM_COMUNICACAO','Atividade para: Aponta para uma parte do corpo quando solicitado.','Brincar de nomear partes do corpo durante o banho ou em frente ao espelho.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000053',18,18,'COGNITIVO','Atividade para: Mostra para que servem objetos comuns.','Brincar de faz-de-conta com objetos do dia a dia, perguntando ''o que a gente faz com isso?''.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000054',18,18,'COGNITIVO','Atividade para: Aponta ou gesticula para pedir ajuda.','Criar situações levemente desafiadoras (pote difícil de abrir) e esperar a criança pedir ajuda por gesto ou som antes de intervir.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000055',18,18,'MOTOR','Atividade para: Sobe e desce de móveis baixos sozinha.','Disponibilizar um móvel baixo e seguro (banquinho, sofá baixo) para praticar subir e descer com supervisão.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000056',18,18,'MOTOR','Atividade para: Come com colher, mesmo derramando um pouco.','Oferecer a colher nas refeições e permitir a tentativa independente, mesmo com sujeira, sem assumir a tarefa.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000057',24,24,'SOCIAL_EMOCIONAL','Atividade para: Percebe quando alguém está triste ou machucado.','Nomear emoções em livros, desenhos ou situações reais, modelando empatia e cuidado.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000058',24,24,'SOCIAL_EMOCIONAL','Atividade para: Brinca de forma mais interativa com outras crianças.','Propor brincadeiras simples com regras curtas em pares (rolar bola, esconde-esconde), mediando a interação.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000059',24,24,'LINGUAGEM_COMUNICACAO','Atividade para: Fala frases de duas palavras.','Expandir o que a criança diz em frases curtas, sem corrigir diretamente.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000060',24,24,'LINGUAGEM_COMUNICACAO','Atividade para: Tem vocabulário de aproximadamente cinquenta palavras.','Leitura diária de livros e narrativa constante do cotidiano, nomeando ações e objetos novos.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000061',24,24,'COGNITIVO','Atividade para: Segue uma instrução de dois passos.','Dar instruções simples em sequência no dia a dia (ex.: ''pega o sapato e traz pra mim''), em contexto familiar.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000062',24,24,'COGNITIVO','Atividade para: Faz brincadeira de faz-de-conta com sequência de dois passos.','Modelar sequências simples de faz-de-conta (dar comida à boneca e depois colocá-la para dormir).','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000063',24,24,'LINGUAGEM_COMUNICACAO','Atividade para: Nomeia pelo menos cinco objetos do dia a dia.','Jogos de ''o que é isso?'' com objetos da casa ou figuras de livros.','Acompanhe o interesse e o ritmo da criança; interrompa se houver cansaço, desconforto ou irritação.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000064',24,24,'MOTOR','Atividade para: Corre e chuta uma bola.','Brincadeiras ao ar livre de correr e chutar bola grande e leve, em espaço seguro.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE),
('30000000-0000-0000-0000-000000000065',24,24,'MOTOR','Atividade para: Constrói uma torre de pelo menos quatro blocos.','Brincar de empilhar blocos junto, aumentando gradualmente a altura e celebrando a tentativa mesmo que caia.','Acompanhe o ritmo da criança, sem forçar posições ou movimentos; mantenha supervisão e ambiente seguro.','Pueria - atividades por marco 0-24 meses (validação clínica)','ESTIMULOS_MARCO_V2_2026_07',TRUE);
